import React from "react";
import { InputField } from "@/components/Form/InputField";
import SelectField from "@/components/Form/SelectField";
import { Address, DestinationAddress, OriginAddress } from "@/types";
import Button from "@/components/Button/Button";
import { TNewAddressError } from "@/types/error";
import { NextRouter } from "next/router";

type TAddressForm = {
  addressData: OriginAddress;
  handleOnChange: (
    e: React.ChangeEvent<HTMLSelectElement | HTMLInputElement>
  ) => void;
  isFormError: TNewAddressError;
  provinceOptions: string[];
  cityOptions: string[];
  router?: NextRouter;
};

const AddressForm = ({
  addressData,
  handleOnChange,
  isFormError,
  provinceOptions,
  cityOptions,
  router,
}: TAddressForm) => {
  return (
    <>
      <InputField
        type="text"
        name="addressName"
        value={addressData.addressName}
        onChange={handleOnChange}
        label="Address Name"
        placeholder="ex: JNE Kuningan"
        err={isFormError.addressName ? "Address must be filled" : ""}
      />
      <InputField
        type="text"
        name="street"
        value={addressData.street}
        onChange={handleOnChange}
        label="Street"
        placeholder="ex: Jl. Ini nama Jalan No. 20, Kuningan, Setiabudi"
        err={isFormError.street ? "Street must be filled" : ""}
      />
      <div className="flex gap-4">
        <SelectField
          id="province"
          name="province"
          onChange={handleOnChange}
          options={provinceOptions}
          label="Province"
          defaultValue={addressData.province ? addressData.province : ""}
          err={isFormError.province ? "Province must be chosen" : ""}
        />
        <SelectField
          id="city"
          name="city"
          onChange={handleOnChange}
          options={cityOptions}
          label="City"
          defaultValue={addressData.city ? addressData.city : ""}
          disabled={addressData.provinceId ? false : true}
          err={isFormError.city ? "City must be chosen" : ""}
        />
      </div>
      <div className="mt-10 flex gap-4">
        <div>
          <Button type="submit" variants="primary">
            Save
          </Button>
        </div>
        <div className="">
          <Button type="button" variants="" onClick={() => router?.back()}>
            Go Back
          </Button>
        </div>
      </div>
    </>
  );
};

export default AddressForm;
