import AddressForm from "@/components/Form/AddressForm";
import AdminLayout from "@/components/Layout/AdminLayout";
import Spinner from "@/components/Loading/Spinner";
import { apiBaseUrl } from "@/config";
import { useCustomSWR } from "@/hooks/useCustomSWR";
import { OriginAddress } from "@/types";
import { TCity, TCityResult, TProvince, TProvinceResult } from "@/types/api";
import { TNewAddressError } from "@/types/error";
import { isValidForm } from "@/utils/formValidation/isValidForm";
import { useRouter } from "next/router";
import React, { FormEvent, useEffect, useState } from "react";
import { Toaster } from "sonner";

const EditAddress = () => {
  const router = useRouter();
  const [originAddressData, setOriginAddressData] = useState<OriginAddress>({
    addressName: "",
    city: "",
    cityId: "",
    province: "",
    provinceId: "",
    street: "",
    createdAt: "",
    updatedAt: "",
  });
  const [isFormError, setIsFormError] = useState<TNewAddressError>({
    addressName: false,
    street: false,
    province: false,
    city: false,
  });
  const [provinceOptions, setProvinceOptions] = useState<string[]>([]);
  const [cityOptions, setCityOptions] = useState<string[]>([]);
  const province = useCustomSWR<TProvinceResult>("/api/getProvince");
  const city = useCustomSWR<TCityResult>(
    originAddressData.provinceId != ""
      ? `/api/getCity?province=${originAddressData.provinceId}`
      : null
  );
  const existingOriginAddress = useCustomSWR<OriginAddress>(
    router.query.addressId
      ? `${apiBaseUrl}/originAddress/${router.query.addressId}`
      : null
  );

  const handleOnChange = (
    e: React.ChangeEvent<HTMLSelectElement | HTMLInputElement>
  ) => {
    if (e.target.name === "province") {
      if (province.data) {
        const selectProvince = province.data.rajaongkir.results.find(
          (value: TProvince) => {
            return value.province === e.target.value;
          }
        );
        if (selectProvince) {
          setOriginAddressData((prevData) => {
            return {
              ...prevData,
              [e.target.name]: selectProvince.province,
              provinceId: selectProvince.province_id,
            };
          });
        }
      }
    } else if (e.target.name === "city") {
      if (city.data && city.data.rajaongkir.results.length != 0) {
        const selectCity = city.data.rajaongkir.results.find((value: TCity) => {
          return value.city_name === e.target.value;
        });
        if (selectCity) {
          setOriginAddressData((prevData) => {
            return {
              ...prevData,
              [e.target.name]: selectCity.city_name,
              cityId: selectCity.city_id,
            };
          });
        }
      }
    } else {
      setOriginAddressData((prevData) => {
        return {
          ...prevData,
          [e.target.name]: e.target.value,
        };
      });
    }
    setIsFormError((prevData) => {
      return {
        ...prevData,
        [e.target.name]: false,
      };
    });
  };

  const onSubmitForm = (e: FormEvent) => {
    e.preventDefault();
    if (isValidForm(originAddressData, setIsFormError)) {
      //   fetchOriginAddress();
      setTimeout(() => {
        router.back();
      }, 1000);
    }
  };

  useEffect(() => {
    if (province.data) {
      const provName = province.data.rajaongkir.results.map(
        (value: TProvince) => value.province
      );

      setProvinceOptions(provName);
    }
  }, [province.data]);

  useEffect(() => {
    if (city.data) {
      const cityName = city.data.rajaongkir.results.map(
        (value: TCity) => value.city_name
      );

      setCityOptions(cityName);
    }
  }, [city.data]);

  useEffect(() => {
    if (existingOriginAddress.data) {
      setOriginAddressData(existingOriginAddress.data);
    }
  }, [existingOriginAddress.data]);

  useEffect(() => {
    console.log(originAddressData);
  }, [originAddressData]);

  return (
    <AdminLayout>
      <Toaster position="top-center" richColors />
      <h1 className="uppercase font-semibold text-2xl text-black pt-14">
        Edit Address
      </h1>
      {originAddressData ? (
        <form className="mt-5" onSubmit={onSubmitForm}>
          <AddressForm
            addressData={originAddressData}
            isFormError={isFormError}
            handleOnChange={handleOnChange}
            provinceOptions={provinceOptions}
            cityOptions={cityOptions}
            router={router}
          />
        </form>
      ) : (
        <Spinner />
      )}
    </AdminLayout>
  );
};

export default EditAddress;
